def qr_decomposition_kernel(A, Q, R, m, n, BLOCK_SIZE=32):
    # Initialize Q and R matrices
    for i in range(m):
        for j in range(n):
            if i == j:
                R[i, j] = A[i, j]
            else:
                R[i, j] = 0.0
            if i == j:
                Q[i, j] = 1.0
            else:
                Q[i, j] = 0.0

    # Apply Givens rotations to compute QR decomposition
    for k in range(min(m, n)):
        # Compute Givens rotation
        for i in range(k + 1, m):
            # Compute the rotation angle
            if R[k, k] != 0.0:
                # Compute cosine and sine
                r_kk = R[k, k]
                r_ik = R[i, k]
                norm = tl.sqrt(r_kk * r_kk + r_ik * r_ik)
                if norm != 0.0:
                    c = r_kk / norm
                    s = r_ik / norm
                else:
                    c = 1.0
                    s = 0.0

                # Apply rotation to R
                temp = R[k, k]
                R[k, k] = c * temp + s * R[k, k]
                R[i, k] = -s * temp + c * R[i, k]

                # Apply rotation to Q
                for j in range(m):
                    temp_q = Q[j, k]
                    Q[j, k] = c * temp_q + s * Q[j, i]
                    Q[j, i] = -s * temp_q + c * Q[j, i]

                # Apply rotation to R
                for j in range(k + 1, n):
                    temp_r = R[k, j]
                    R[k, j] = c * temp_r + s * R[i, j]
                    R[i, j] = -s * temp_r + c * R[i, j]

