def sum_kernel(
    input_ptr,
    output_ptr,
    num_rows,
    num_cols,
    BLOCK_SIZE: tl.constexpr,
):
    row_idx = tl.program_id(0)
    if row_idx >= num_rows:
        return

    output = tl.zeros((1,), dtype=tl.float32)
    for col_start in range(0, num_cols, BLOCK_SIZE):
